import React from 'react';
import { motion } from 'framer-motion';

interface ArenaButtonProps {
  children: React.ReactNode;
  variant?: 'primary' | 'outline' | 'ghost';
  onClick?: () => void;
  className?: string;
  icon?: React.ReactNode;
}

const ArenaButton: React.FC<ArenaButtonProps> = ({ 
  children, 
  variant = 'primary', 
  onClick, 
  className = '',
  icon
}) => {
  const baseStyles = "relative px-8 py-4 font-syncopate text-[10px] font-bold tracking-[0.2em] uppercase overflow-hidden transition-all duration-300 flex items-center justify-center gap-3 group";

  const variants = {
    primary: "bg-yellow-500 text-black hover:bg-yellow-400",
    outline: "border border-slate-700 text-white hover:border-yellow-500 hover:text-yellow-500 bg-transparent",
    ghost: "text-slate-400 hover:text-white"
  };

  return (
    <motion.button 
      whileHover={{ scale: 1.02 }}
      whileTap={{ scale: 0.98 }}
      onClick={onClick}
      className={`${baseStyles} ${variants[variant]} ${className}`}
    >
      <span className="relative z-10 flex items-center gap-2">
        {children}
        {icon}
      </span>
      {variant === 'primary' && (
        <motion.div 
          className="absolute inset-0 bg-white/20 translate-x-[-100%] group-hover:translate-x-[100%] transition-transform duration-700 ease-in-out"
        />
      )}
    </motion.button>
  );
};

export default ArenaButton;

