const Schedule = () => {
  const [filter, setFilter] = useState<'ALL' | 'LIVE' | 'UPCOMING' | 'FINISHED'>('ALL');
  const [selectedEventId, setSelectedEventId] = useState<string>(MOCK_EVENTS[0].id);

  const filteredEvents = useMemo(() => {
    const list = MOCK_EVENTS.filter(e => filter === 'ALL' || e.status === filter);
    return list;
  }, [filter]);

  // Auto-select first event when filter changes
  useEffect(() => {
    if (filteredEvents.length > 0) {
      // Keep selection if it's in the new list, otherwise select first
      const exists = filteredEvents.find(e => e.id === selectedEventId);
      if (!exists) {
        setSelectedEventId(filteredEvents[0].id);
      }
    }
  }, [filteredEvents, selectedEventId]);

  const selectedEvent = useMemo(() => 
    MOCK_EVENTS.find(e => e.id === selectedEventId) || filteredEvents[0],
    [selectedEventId, filteredEvents]
  );

  return (
    <div className="min-h-screen pt-40 pb-40 px-6 relative">
      <div className="fixed inset-0 bg-grid opacity-10 pointer-events-none" />
      <div className="fixed inset-0 bg-scanline opacity-20 pointer-events-none z-10" />

      <div className="max-w-7xl mx-auto relative z-20">
        <ScheduleHeader />

        {/* Segmented Filter Control */}
        <div className="flex flex-wrap gap-2 mb-12 p-1.5 bg-slate-900/80 border border-slate-800 w-fit">
          {(['ALL', 'LIVE', 'UPCOMING', 'FINISHED'] as const).map(f => (
            <button 
              key={f}
              onClick={() => setFilter(f)}
              className={`font-syncopate text-[9px] tracking-[0.2em] font-bold px-6 py-3 transition-all
                ${filter === f 
                  ? 'bg-[#FFC400] text-black shadow-[0_0_15px_rgba(255,196,0,0.3)]' 
                  : 'text-slate-500 hover:text-white hover:bg-slate-800'
                }`}
            >
              {f}
            </button>
          ))}
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-12 gap-8 items-start">

          {/* LEFT: Scrollable Event List */}
          <div className="lg:col-span-4 max-h-[700px] overflow-y-auto pr-2 custom-scrollbar">
            {filteredEvents.length > 0 ? (
              <div className="space-y-1">
                {filteredEvents.map((event) => (
                  <EventListItem 
                    key={event.id}
                    event={event}
                    isActive={selectedEventId === event.id}
                    onClick={() => setSelectedEventId(event.id)}
                  />
                ))}
              </div>
            ) : (
              <div className="p-12 border border-dashed border-slate-800 text-center">
                <span className="font-syncopate text-[10px] text-slate-600 uppercase tracking-widest">No operations matching criteria</span>
              </div>
            )}
          </div>

          {/* RIGHT: Sticky Detail Panel */}
          <div className="lg:col-span-8 lg:sticky lg:top-32 h-[700px]">
            <AnimatePresence mode="wait">
              {selectedEvent ? (
                <DetailPanel event={selectedEvent} />
              ) : (
                <div className="bg-[#081B3A] border border-slate-800 h-full flex items-center justify-center">
                   <Activity className="text-slate-800" size={64} />
                </div>
              )}
            </AnimatePresence>

            {/* HUD Footer Information */}
            <div className="mt-4 flex justify-between items-center px-2 opacity-40">
              <div className="flex gap-2">
                {[1, 2, 3, 4].map(i => (
                  <div key={i} className="w-1 h-1 bg-slate-500" />
                ))}
              </div>
              <div className="font-syncopate text-[7px] text-slate-500 tracking-[0.4em] uppercase">
                ENCRYPTED_FEED // ARENA_SYNC_v2 // DUBAI_CORE
              </div>
            </div>
          </div>

        </div>
      </div>

      {/* Subtle Sidebar Indicators */}
      <div className="fixed left-6 bottom-10 hidden xl:flex flex-col gap-6 opacity-20">
        <div className="flex flex-col gap-1">
          <span className="font-syncopate text-[7px] text-slate-500 uppercase">LATENCY</span>
          <span className="font-syncopate text-[9px] text-[#FFC400] font-bold">12 MS</span>
        </div>
        <div className="flex flex-col gap-1">
          <span className="font-syncopate text-[7px] text-slate-500 uppercase">PACKETS</span>
          <span className="font-syncopate text-[9px] text-[#FFC400] font-bold">0.0% LOSS</span>
        </div>
      </div>
    </div>
  );
};

