        {/* Scan Line Animation (on hover) */}
        <AnimatePresence>
          {isHovered && (
            <motion.div
              initial={{ left: '-100%' }}
              animate={{ left: '100%' }}
              exit={{ opacity: 0 }}
              transition={{ duration: 0.8, ease: "easeInOut" }}
