      <motion.div 
        animate={{ opacity: [0.3, 0.5, 0.3], scale: [1, 1.1, 1] }}
        transition={{ duration: 8, repeat: Infinity, ease: "easeInOut" }}
        className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[300px] md:w-[1000px] h-[300px] md:h-[1000px] bg-[#FFC400]/5 rounded-full blur-[80px] md:blur-[150px] z-0" 
      />

      <motion.div 
        style={{ y: springY, opacity: opacityRange, scale: scaleRange }}
        className="container mx-auto px-6 md:px-12 relative z-30"
      >
        <div className="grid grid-cols-1 lg:grid-cols-2 items-center gap-12 lg:gap-32">
          <div className="flex flex-col items-center lg:items-start text-center lg:text-left">
            <motion.div
