            </motion.div>

            <div className="relative mb-8 md:mb-16">
              <div className="flex flex-col gap-1 lg:gap-2">
                <motion.h2 
                  initial={{ opacity: 0, x: -100, filter: "blur(20px)" }}
                  animate={{ opacity: 1, x: 0, filter: "blur(0px)" }}
                  transition={{ duration: 0.8, delay: 0.8 }}
                  className="font-syncopate text-3xl md:text-6xl lg:text-7xl font-black text-white uppercase tracking-tighter leading-none"
                >GEAR UP.</motion.h2>
                <motion.h2 
                  initial={{ opacity: 0, y: 50 }}
                  animate={{ opacity: 1, y: 0 }}
                  transition={{ duration: 0.7, delay: 1.5 }}
                  className="font-syncopate text-3xl md:text-6xl lg:text-7xl font-black text-white uppercase tracking-tighter leading-none"
                >LEVEL UP.</motion.h2>
                <div className="relative pt-2">
                  <Shockwave trigger={dominateTrigger} />
                  <motion.h1 
                    initial={{ opacity: 0, scale: 0.5, filter: "blur(40px)" }}
                    animate={{ opacity: 1, scale: 1, filter: "blur(0px)" }}
                    transition={{ duration: 0.6, delay: 2.2 }}
                    className="font-syncopate text-4xl md:text-[80px] lg:text-[100px] font-black text-[#FFC400] uppercase tracking-tighter leading-none drop-shadow-[0_0_20px_rgba(255,196,0,0.5)]"
                  >DOMINATE.</motion.h1>
                </div>
              </div>
            </div>

            <motion.div 
