const EcosystemGraph = () => {
  const nodes = [
    { icon: <Twitter size={18} />, angle: 0, label: "TWITTER", stats: "450K" },
    { icon: <Twitch size={18} />, angle: 60, label: "TWITCH", stats: "1.2M" },
    { icon: <Instagram size={18} />, angle: 120, label: "INSTAGRAM", stats: "620K" },
    { icon: <Youtube size={18} />, angle: 180, label: "YOUTUBE", stats: "180K" },
    { icon: <Zap size={18} />, angle: 240, label: "TIKTOK", stats: "800K" },
    { icon: <MessageCircle size={18} />, angle: 300, label: "DISCORD", stats: "150K" },
  ];

  return (
    <div className="relative w-full aspect-square max-w-[300px] md:max-w-[600px] mx-auto flex items-center justify-center scale-90 md:scale-100">
      <div className="absolute inset-0 border border-slate-800/40 rounded-full" />
      <motion.div animate={{ rotate: 360 }} transition={{ duration: 40, repeat: Infinity, ease: "linear" }} className="absolute w-full h-full border border-slate-800/20 rounded-full" />

      <div className="w-20 h-20 md:w-40 md:h-40 bg-[#FFC400] rounded-full flex flex-col items-center justify-center z-20 text-black shadow-[0_0_50px_rgba(255,196,0,0.3)]">
        <span className="font-syncopate font-black text-xs md:text-xl">GEEKAY</span>
      </div>

      {nodes.map((node, i) => {
        const radius = window.innerWidth < 768 ? 130 : 250;
        const x = Math.cos((node.angle * Math.PI) / 180) * radius;
        const y = Math.sin((node.angle * Math.PI) / 180) * radius;
        return (
          <div key={i} className="absolute z-30 flex flex-col items-center group" style={{ left: `calc(50% + ${x}px)`, top: `calc(50% + ${y}px)`, transform: 'translate(-50%, -50%)' }}>
            <div className="bg-[#081B3A] border border-slate-800 p-2 md:p-4 rounded-xl group-hover:border-[#FFC400] transition-all">
              <div className="text-[#FFC400]">{node.icon}</div>
            </div>
            <div className="absolute -bottom-10 opacity-0 group-hover:opacity-100 transition-all pointer-events-none text-center min-w-[100px]">
              <div className="font-syncopate text-[8px] text-[#FFC400] font-black">{node.stats}</div>
              <div className="font-syncopate text-[6px] text-slate-500 uppercase">{node.label}</div>
            </div>
          </div>
        );
      })}
    </div>
  );
};

